INSERT INTO public.instructors (name, title, bio, specialization, image_url, email, phone, years_experience) VALUES
('Dr. Kwame Boateng', 'Director & Head of Piano Studies', 'With over 25 years of experience, Dr. Boateng has trained hundreds of professional pianists. He holds a Doctorate in Music from the University of Ghana.', ARRAY['Classical Piano', 'Worship Music', 'Music Theory'], 'https://images.pexels.com/photos/220453/pexels-photo-220453.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 'kwame@resonance.edu.gh', '+233 53 848 0868', 25),
('Ama Asantewaa', 'Head of Vocal Training', 'A professional vocalist with experience performing internationally. Ama specializes in contemporary gospel and traditional African music.', ARRAY['Vocal Technique', 'Gospel Music', 'Performance'], 'https://images.pexels.com/photos/1239291/pexels-photo-1239291.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 'ama@resonance.edu.gh', '+233 54 111 2222', 15),
('Kofi Mensah', 'Head of Guitar Studies', 'Kofi is a versatile guitarist proficient in classical, jazz, and contemporary styles. He has taught guitar for over 18 years.', ARRAY['Classical Guitar', 'Electric Guitar', 'Bass'], 'https://images.pexels.com/photos/1222271/pexels-photo-1222271.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 'kofi@resonance.edu.gh', '+233 54 333 4444', 18),
('Nana Yaw Osei', 'Head of Percussion Studies', 'A master drummer who has performed with top African artists. Nana Yaw brings traditional and modern drumming techniques to his teaching.', ARRAY['Drum Set', 'Traditional Percussion', 'Rhythm Theory'], 'https://images.pexels.com/photos/2379005/pexels-photo-2379005.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 'nana@resonance.edu.gh', '+233 54 555 6666', 20),
('Efua Darko', 'Head of Music Production', 'Efua is a certified audio engineer with experience in music production for film, television, and recording studios.', ARRAY['Music Production', 'Audio Engineering', 'Sound Design'], 'https://images.pexels.com/photos/1181686/pexels-photo-1181686.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 'efua@resonance.edu.gh', '+233 54 777 8888', 12),
('Samuel Addo', 'Head of Worship Music', 'Samuel has served as music director for major churches across Ghana and brings practical worship ministry experience to his teaching.', ARRAY['Worship Leading', 'Church Music', 'Choir Direction'], 'https://images.pexels.com/photos/774909/pexels-photo-774909.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 'samuel@resonance.edu.gh', '+233 54 999 0000', 16);
INSERT INTO public.courses (name, slug, description, full_description, duration_weeks, level, price, certificate_offered, image_url, instructor_id, featured, capacity, rating, features) VALUES
('Piano & Keyboard', 'piano-keyboard', 'Master the piano from basics to advanced performance. Learn classical, contemporary, and worship styles.', 'Our Piano & Keyboard program is designed to take you from complete beginner to confident performer. You will learn proper technique, music reading, chord progressions, and performance skills. The curriculum covers classical, contemporary, gospel, and worship music styles.', 24, 'beginner', 1500, true, 'https://images.pexels.com/photos/1246321/pexels-photo-1246321.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Dr. Kwame Boateng'), true, 20, 4.9, ARRAY['One-on-one lessons', 'Practice room access', 'Certificate upon completion', 'Recording opportunities', 'Performance workshops']),
('Guitar Mastery', 'guitar', 'From acoustic to electric, learn chords, scales, fingerpicking, and lead guitar techniques for various genres.', 'Whether you want to strum acoustic songs or shred on electric guitar, this comprehensive program covers it all. Learn chords, scales, music theory, fingerpicking, and lead techniques.', 20, 'intermediate', 1200, true, 'https://images.pexels.com/photos/1407354/pexels-photo-1407354.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Kofi Mensah'), true, 15, 4.8, ARRAY['Acoustic & Electric techniques', 'Group jam sessions', 'Performance training', 'Songwriting basics', 'Certificate upon completion']),
('Drum Performance', 'drums', 'Learn rhythm patterns, fills, and techniques for various genres including gospel, jazz, and contemporary music.', 'Drum Performance covers fundamental rhythm concepts, stick control, and coordination. Learn to play gospel, jazz, contemporary, and traditional African rhythms.', 16, 'beginner', 1000, true, 'https://images.pexels.com/photos/174630/pexels-photo-174630.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Nana Yaw Osei'), true, 12, 4.7, ARRAY['Professional drum kits', 'Practice pads provided', 'Play-along tracks', 'Band integration', 'Certificate upon completion']),
('Vocal Training', 'vocal', 'Develop your voice, breathing techniques, pitch accuracy, and performance confidence.', 'Our Vocal Training program helps you discover and develop your unique voice. Learn proper breathing, pitch control, vocal exercises, and performance techniques.', 12, 'beginner', 800, true, 'https://images.pexels.com/photos/167491/pexels-photo-167491.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Ama Asantewaa'), true, 25, 4.9, ARRAY['Breathing techniques', 'Vocal exercises', 'Song interpretation', 'Stage presence', 'Certificate upon completion']),
('Music Theory', 'music-theory', 'Understand the building blocks of music including scales, intervals, chords, and harmony.', 'Music Theory provides the foundation for all musical understanding. Learn to read and write music, understand chord progressions, and analyze musical compositions.', 12, 'beginner', 600, true, 'https://images.pexels.com/photos/256431/pexels-photo-256431.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Efua Darko'), false, 30, 4.6, ARRAY['Music notation', 'Harmony analysis', 'Ear training', 'Composition basics', 'Certificate upon completion']),
('Music Production', 'music-production', 'Learn to produce professional-quality music using industry-standard software and equipment.', 'Music Production teaches you to create, record, mix, and master music using professional digital audio workstations. Learn sound design, mixing techniques, and music business basics.', 20, 'intermediate', 2000, true, 'https://images.pexels.com/photos/1595385/pexels-photo-1595385.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Efua Darko'), true, 10, 4.8, ARRAY['DAW training', 'Mixing & Mastering', 'Sound design', 'Studio access', 'Certificate upon completion']),
('Bass Guitar', 'bass-guitar', 'Master the fundamentals of bass playing including technique, theory, and groove.', 'Bass Guitar program covers proper technique, finger style and pick playing, groove and timing, and music theory specifically for bassists.', 16, 'beginner', 1000, true, 'https://images.pexels.com/photos/169441/pexels-photo-169441.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Kofi Mensah'), false, 10, 4.7, ARRAY['Technique Mastery', 'Groove training', 'Theory application', 'Band workshops', 'Certificate upon completion']),
('Church Music', 'church-music', 'Specialized training for worship musicians including song leading, arrangement, and ministry.', 'Church Music program prepares you for music ministry. Learn worship leading, song arrangement, choir direction, and practical ministry skills.', 16, 'intermediate', 1200, true, 'https://images.pexels.com/photos/1199816/pexels-photo-1199816.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Samuel Addo'), false, 20, 4.9, ARRAY['Worship leading', 'Song arrangement', 'Choir direction', 'Ministry ethics', 'Certificate upon completion']),
('Ear Training', 'ear-training', 'Develop your ability to identify pitches, intervals, chords, and rhythms by ear.', 'Ear Training develops your musical hearing. Learn to identify intervals, chords, scales, and rhythms. Essential skill for all musicians.', 8, 'beginner', 500, true, 'https://images.pexels.com/photos/1644888/pexels-photo-1644888.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Dr. Kwame Boateng'), false, 40, 4.6, ARRAY['Interval recognition', 'Chord identification', 'Rhythm training', 'Dictation practice', 'Certificate upon completion']),
('Sight Reading', 'sight-reading', 'Learn to read and perform music at first sight with speed and accuracy.', 'Sight Reading teaches you to read and perform music notation fluently. Essential for session musicians and ensemble players.', 8, 'intermediate', 500, true, 'https://images.pexels.com/photos/256431/pexels-photo-256431.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Dr. Kwame Boateng'), false, 25, 4.5, ARRAY['Note reading', 'Rhythm reading', 'Key signatures', 'Practice materials', 'Certificate upon completion']),
('Song Writing', 'songwriting', 'Learn the art and craft of writing memorable songs including lyrics, melody, and structure.', 'Song Writing covers lyric composition, melody creation, song structure, and the creative process. Turn your ideas into complete songs.', 12, 'intermediate', 800, true, 'https://images.pexels.com/photos/1672735/pexels-photo-1672735.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Ama Asantewaa'), false, 15, 4.8, ARRAY['Lyric writing', 'Melody creation', 'Song structure', 'Copyright basics', 'Certificate upon completion']),
('Band Training', 'band-training', 'Learn to play effectively in a band setting, including communication, arrangement, and performance.', 'Band Training prepares you for real-world ensemble playing. Learn communication, arrangement, rehearsal techniques, and live performance.', 12, 'intermediate', 1000, true, 'https://images.pexels.com/photos/1672735/pexels-photo-1672735.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Nana Yaw Osei'), false, 12, 4.7, ARRAY['Ensemble playing', 'Communication', 'Arrangement', 'Live performance', 'Certificate upon completion']);
INSERT INTO public.testimonials (student_name, course, testimonial, rating, image_url, is_featured) VALUES
('Kwame Asante', 'Piano & Keyboard', 'Resonance Music Institute transformed my musical journey. The instructors are incredibly patient and skilled. I went from knowing nothing about piano to playing in my church within 6 months!', 5, 'https://images.pexels.com/photos/2379005/pexels-photo-2379005.jpeg?auto=compress&cs=tinysrgb&w=150&q=80', true),
('Ama Serwaa', 'Vocal Training', 'The vocal training program helped me discover my true voice. My confidence has skyrocketed, and I now lead worship at my church. Best decision I ever made!', 5, 'https://images.pexels.com/photos/1239291/pexels-photo-1239291.jpeg?auto=compress&cs=tinysrgb&w=150&q=80', true),
('Kofi Mensah', 'Guitar', 'I love the flexible class schedules and the small class sizes. My instructor took time to understand my goals and tailored the lessons accordingly. Highly recommend!', 5, 'https://images.pexels.com/photos/220453/pexels-photo-220453.jpeg?auto=compress&cs=tinysrgb&w=150&q=80', true),
('Adwoa Agyeman', 'Music Production', 'The music production course opened up a whole new world for me. I have already produced songs for local artists and started my own studio business.', 4, 'https://images.pexels.com/photos/774909/pexels-photo-774909.jpeg?auto=compress&cs=tinysrgb&w=150&q=80', true),
('Yaw Osei', 'Drums', 'From complete beginner to playing in a band in 8 months! The drum program here is exceptional. The practice rooms are well-equipped too.', 5, 'https://images.pexels.com/photos/1222271/pexels-photo-1222271.jpeg?auto=compress&cs=tinysrgb&w=150&q=80', false),
('Efua Darko', 'Music Theory', 'I thought music theory would be boring, but the way it is taught here makes it so engaging. It has improved my overall musicianship tremendously.', 5, 'https://images.pexels.com/photos/1181686/pexels-photo-1181686.jpeg?auto=compress&cs=tinysrgb&w=150&q=80', false);
