INSERT INTO public.events (title, description, event_date, event_time, location, image_url, event_type, is_featured, max_attendees, registration_fee) VALUES
('Keyboard Masterclass', 'A special workshop with renowned pianist Dr. Kwame Boateng. Learn advanced techniques, improvisation, and performance tips.', '2026-07-15', '14:00', 'Main Auditorium, Resonance Campus', 'https://images.pexels.com/photos/1246321/pexels-photo-1246321.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', 'masterclass', true, 50, 150),
('Gospel Music Concert', 'Celebrate the spirit of gospel music with our talented students and special guest artists. A night of praise and worship.', '2026-07-22', '18:00', 'National Theatre, Accra', 'https://images.pexels.com/photos/1199816/pexels-photo-1199816.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', 'concert', true, 500, 100),
('Summer Graduation Ceremony', 'Celebrating the achievements of our graduating class. Join us for a memorable ceremony featuring student performances.', '2026-08-05', '10:00', 'Resonance Campus Auditorium', 'https://images.pexels.com/photos/267554/pexels-photo-267554.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', 'graduation', true, 200, 0),
('Guitar Workshop', 'Interactive session covering fingerpicking, solo techniques, and chord progressions. For intermediate players.', '2026-08-12', '15:00', 'Guitar Lab, Resonance Campus', 'https://images.pexels.com/photos/1407354/pexels-photo-1407354.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', 'workshop', false, 25, 120),
('Choir Auditions', 'Open auditions for our worship choir. Open to all skill levels. Preparation required.', '2026-09-02', '09:00', 'Choir Room, Resonance Campus', 'https://images.pexels.com/photos/1199816/pexels-photo-1199816.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', 'audition', false, 100, 0),
('Drum Clinic with Nana Yaw', 'Special drum clinic with Master Drummer Nana Yaw Osei. Learn traditional and contemporary drumming techniques.', '2026-09-15', '14:00', 'Drum Studio, Resonance Campus', 'https://images.pexels.com/photos/174630/pexels-photo-174630.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', 'masterclass', false, 30, 200);
INSERT INTO public.blog_posts (title, slug, excerpt, content, category, tags, image_url, author_id, author_name, published, published_at, read_time) VALUES
('5 Essential Practice Techniques for Piano Beginners', 'piano-practice-techniques', 'Master the art of effective piano practice with these proven techniques that will accelerate your learning journey.', 'Learning to play the piano is a rewarding journey, but without proper practice techniques, progress can be slow and frustrating. Here are five essential practice techniques that every beginner should know...', 'Piano Tips', ARRAY['piano', 'practice', 'beginners', 'techniques'], 'https://images.pexels.com/photos/1246321/pexels-photo-1246321.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Dr. Kwame Boateng'), 'Dr. Kwame Boateng', true, '2026-06-20', '5 min read'),
('Finding Your Unique Voice in Gospel Music', 'gospel-music-voice', 'Learn how to develop your distinctive sound and style in gospel music while staying true to the tradition.', 'Gospel music has a rich heritage that spans generations. As a musician, finding your unique voice within this tradition requires both respect for the past and creative innovation...', 'Worship Music', ARRAY['gospel', 'worship', 'voice', 'style'], 'https://images.pexels.com/photos/167491/pexels-photo-167491.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Samuel Addo'), 'Samuel Addo', true, '2026-06-15', '7 min read'),
('Understanding Music Theory: A Beginner''s Guide', 'music-theory-guide', 'Demystify music theory with this comprehensive guide designed for complete beginners.', 'Music theory often seems intimidating, but it doesnt have to be. At its core, music theory is simply the language we use to describe and understand music...', 'Music Theory', ARRAY['theory', 'beginners', 'fundamentals', 'scales'], 'https://images.pexels.com/photos/256431/pexels-photo-256431.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Efua Darko'), 'Efua Darko', true, '2026-06-10', '10 min read'),
('From Student to Studio: A Graduate''s Success Story', 'student-success-story', 'Read how Kwame Asante transformed his passion for music into a flourishing career after graduating from Resonance.', 'When Kwame Asante enrolled at Resonance Music Institute in 2018, he had no idea his journey would lead to opening his own recording studio...', 'Success Stories', ARRAY['success', 'graduates', 'inspiration', 'career'], 'https://images.pexels.com/photos/1595385/pexels-photo-1595385.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', NULL, 'Editorial Team', true, '2026-06-05', '6 min read'),
('Drumming for Worship: Rhythm in Gospel Services', 'drumming-worship', 'Discover the role of drums in modern gospel services and how to play with sensitivity and power.', 'Drums in worship music require a unique approach. Unlike secular performances, worship drumming is about serving the congregation and enhancing the spiritual atmosphere...', 'Drums', ARRAY['drums', 'worship', 'rhythm', 'gospel'], 'https://images.pexels.com/photos/174630/pexels-photo-174630.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Nana Yaw Osei'), 'Nana Yaw Osei', true, '2026-05-28', '8 min read'),
('The Art of Live Performance: Tips from the Stage', 'live-performance-tips', 'Get expert advice on overcoming stage fright and delivering memorable live performances.', 'Performing live is one of the most rewarding aspects of being a musician. However, even seasoned performers can struggle with stage fright...', 'Performance', ARRAY['performance', 'stage', 'confidence', 'tips'], 'https://images.pexels.com/photos/1672735/pexels-photo-1672735.jpeg?auto=compress&cs=tinysrgb&w=800&q=80', (SELECT id FROM public.instructors WHERE name = 'Ama Asantewaa'), 'Ama Asantewaa', true, '2026-05-20', '6 min read');
INSERT INTO public.products (name, slug, description, price, category, image_url, stock, is_digital, rating, reviews) VALUES
('Keyboard Unlocked: Complete Guide', 'keyboard-unlocked', 'A comprehensive guide for learning keyboard from beginner to advanced. Includes video lessons access.', 89, 'book', 'https://images.pexels.com/photos/256431/pexels-photo-256431.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 50, true, 4.8, 45),
('Music Theory Made Easy', 'music-theory-easy', 'Simple approach to understanding music theory. Perfect for beginners.', 69, 'book', 'https://images.pexels.com/photos/1644888/pexels-photo-1644888.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 35, true, 4.9, 32),
('M-Audio Keystation 88 Key', 'm-audio-keystation', 'Professional 88-key MIDI controller keyboard with semi-weighted keys.', 1250, 'instrument', 'https://images.pexels.com/photos/1246321/pexels-photo-1246321.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 8, false, 4.7, 18),
('Sustain Pedal Pro', 'sustain-pedal', 'Professional piano-style sustain pedal compatible with most keyboards and digital pianos.', 79, 'accessory', 'https://images.pexels.com/photos/1246321/pexels-photo-1246321.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 25, false, 4.5, 12),
('Resonance Branded T-Shirt', 'resonance-tshirt', 'Premium quality cotton t-shirt with the Resonance logo. Available in multiple sizes.', 59, 'apparel', 'https://images.pexels.com/photos/996321/pexels-photo-996321.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 100, false, 4.6, 24),
('Practice Notebook', 'practice-notebook', 'Dedicated notebook for tracking your practice sessions and musical progress.', 25, 'material', 'https://images.pexels.com/photos/546819/pexels-photo-546819.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 80, false, 4.4, 8),
('Beginner Guitar Pack', 'beginner-guitar', 'Acoustic guitar starter pack with gig bag, pick, and spare strings.', 450, 'instrument', 'https://images.pexels.com/photos/1407354/pexels-photo-1407354.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 12, false, 4.7, 22),
('Digital Metronome', 'digital-metronome', 'Digital metronome with multiple time signatures and tempo ranges.', 49, 'accessory', 'https://images.pexels.com/photos/1644888/pexels-photo-1644888.jpeg?auto=compress&cs=tinysrgb&w=400&q=80', 45, false, 4.8, 15);
